var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정신차려! 이 근육 바보야!","JPN":"しっかりして！　この脳筋バカ！","ENG":"Wake up, you muscle-bound idiot!","TWN":"肌肉傻瓜！你醒醒！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"대체 어쩌다가 이런 꼴이 된 거야?","JPN":"いったい何をしたらこんなことになるの！？","ENG":"What happened to you?","TWN":"你怎麼會變成這樣？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"6번 수술실 준비되었습니다! 실비아 씨, 지금 바로 이송해야 합니다!","JPN":"6番手術室の用意ができました！\\nシルビアさん、すぐに移送しなければいけません！","ENG":"Operation Room #6 is ready! Sylvia, we have to move him now!","TWN":"6號手術室已經準備妥當！希爾維亞，必須立刻送他進手術室！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 멍청이 괜찮은 거 맞지? 혹시 잘못 되는 거 아니지?","JPN":"このバカ、大丈夫なんだよね？　治療すれば治るよね？","ENG":"He will be okay, right? Tell me that idiot will be okay!","TWN":"這個傻瓜沒事吧？應該不會有事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……과도한 능력 사용으로 번개가 역류해서 자신의 몸까지 태워 버린 것으로 보입니다.","JPN":"……過度な能力使用で電力が逆流してしまい、\\n自身の体まで燃えてしまったようです。","ENG":"It looks like he overused his power and it backfired on him, burning his body.","TWN":"……可能是因為他過度使用能力，導致閃電逆流燒到自己的身上。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"일반적인 카운터라면 그럴 일이 없겠지만 대령님은 CRF 출력이 너무 강력해서……","JPN":"普通のカウンターならそんなことは起こらないと思いますが、\\n大佐はCRF出力があまりにも強すぎて……","ENG":"If he was an ordinary Counter, this wouldn't have happened, but the Colonel has such a high CRF output...","TWN":"通常一般的制裁者不會發生這種事，但上校的CRF輸出太強……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그딴 건 안 궁금해! 아무튼 괜찮은 거냐고?!","JPN":"そんなことを聞いてるんじゃないわよ！\\nとにかく彼は大丈夫なのかって聞いてるの！","ENG":"I didn’t ask that! I asked if he was going to be okay!","TWN":"我不想知道這些！我只想知道他是不是沒事？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실…… 비아……","JPN":"シル……ビア……","ENG":"Sylvia...","TWN":"希……爾維亞……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님!","JPN":"大佐！","ENG":"Colonel!","TWN":"上校！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저, 정신이 들어? 이 멍청아! 대체 무슨 일을 저지른 거야!","JPN":"だ、大丈夫？　このバカ！　いったい何をしたの！？","ENG":"A-are you awake? You idiot! What have you done?","TWN":"你…你醒了嗎？你這個傻瓜！你到底做了什麼！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"중장님께 배운 대로…… 해야 할 일을 했을 뿐이야……","JPN":"中将に教わったとおり……やるべきことをしただけさ……","ENG":"I did... what the Lieutenant General taught me...","TWN":"我只是照著中將教我的……做我該做的事……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"걱정 마…… 이 정도로 죽을 만큼…… 내가 약골로…… 보여……?","JPN":"心配すんな……この程度でくたばるほど……俺はヤワ……じゃないぞ……","ENG":"Don’t worry... I won’t die... I’m not that weak...","TWN":"放心……這點小傷死不了的……我有……那麼弱嗎……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당연히 아니지!","JPN":"わかってるわよ！","ENG":"Of course not!","TWN":"當然不是！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아씨! 이제 정말 이송해야 합니다!","JPN":"シルビアさん！　もう移送しないと！","ENG":"Sylvia, he really has to go!","TWN":"希爾維亞！真的該送他進手術室了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 알았어!","JPN":"わ、わかったわよ！","ENG":"O-okay!","TWN":"喔…好！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죄송합니다……. 제가 조금만 더 잘했다면 이런 일은 없었을 텐데…….","JPN":"すみません……私がもっとうまくやれたらこんなことには……","ENG":"I’m sorry... I should have done better...","TWN":"抱歉……都怪我不夠堅強，才會發生這種事……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당신도 온 몸이 만신창이로 보이는데…….","JPN":"アンタも全身にひどい怪我をしてるじゃない……","ENG":"But you’re seriously hurt, too...","TWN":"我看你也傷得不輕……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……사과하지 마. 저 바보가 이 정도로 죽을 녀석은 절대 아니니까.","JPN":"……謝らないで。あのバカはこの程度で死ぬようなやつじゃないから。","ENG":"Don’t apologize. That idiot won’t die. Never.","TWN":"……不用道歉，那個傻瓜才不會因為這樣就死掉！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……그래서 미증유의 강력한 침식체가 나타난 것 같다고?","JPN":"……それで未曾有の強力な侵食体が現れただと？","ENG":"... So, we have an unprecedented Corrupted Object in our vicinity?","TWN":"……你說那個侵蝕體的強度是前所未見的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 주시윤 선배가 전투불능이 된 우리 대신 그 괴물의 공격을 전부 받아냈어.","JPN":"うん、アキヤマ先輩が戦闘不能になった私たちの代わりに、\\nあの化け物の攻撃をすべて受け止めたの。","ENG":"Yes. Joo Shiyoon deflected its attacks while we were down.","TWN":"嗯，是周時雲前輩代替無法作戰的我們，擋下那個怪物的所有攻擊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래, 아슬아슬했지…….","JPN":"ああ、ギリギリだったぜ……","ENG":"Yes, it was very close...","TWN":"是啊，真是很驚險呢……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"마지막 순간에 그 소년이 공간을 베고 우릴 상위 차원으로 대피시키지 않았으면 전부 죽었을 거야.","JPN":"最後の瞬間にあの少年が空間を斬って、俺たちを上位次元に避難させてくれなかったら全滅していただろう。","ENG":"If the boy didn’t tear a hole in spacetime to send us to the upper dimension, we all would have died.","TWN":"最後要不是那個年輕人劃開空間，讓我們可以躲到上位次元，我們應該全都沒命回來吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"공간을 베었다……. 대단하군.","JPN":"空間を斬ったとは……凄まじい力だな。","ENG":"So he cut spacetime to open up a path to the upper dimension? That’s impressive.","TWN":"劃開空間……真是厲害！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서 그 소년은 지금 어디 있지?","JPN":"それで、その少年は今どこに？","ENG":"Where is the boy now?","TWN":"那個年輕人現在在哪裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모르겠어…… 빠져 나온 건 우리뿐이니까……","JPN":"わからない……抜け出せたのは私たちだけだから……","ENG":"I don’t know... He didn’t come with us...","TWN":"不知道……只有我們逃出來……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 선배라면 분명 살아 있을 거야!","JPN":"でも先輩ならきっと生きているよ！","ENG":"But I’m sure Shiyoon is still alive!","TWN":"但我相信前輩一定還活著的！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……나도 그렇게 생각하네. 상황이 좋아지는 대로 최대한의 수색을 약속하지.","JPN":"……私も同感だ。状況が良くなり次第、\\nなるべく迅速に捜索すると約束しよう。","ENG":"... I believe you. I will search for him when the situation gets better.","TWN":"……我也這麼認為。我答應你，等情況穩定後，我立刻派人去搜尋他的下落。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……고마워.","JPN":"……ありがとう。","ENG":"Thank you.","TWN":"……謝謝。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데 어떻게 우리가 빠져 나온 곳에 이렇게 맞춰서 구하러 나타난 거지?","JPN":"ところで、どうやって俺たちの場所をピンポイントで見つけて助けに来れたんだ？","ENG":"But how did you get to us so quick?","TWN":"不過怎麼這麼剛好，你們就出現在我們逃出來的地方？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무리 군의 정보력이라고 해도 이렇게 신속하게 대응할 수는 없었을 텐데.","JPN":"軍の情報力とはいえ、いくらなんでもここまで迅速に対応することは難しいと思うが……","ENG":"The response was way too fast, even for the military.","TWN":"就算軍隊的情報能力再怎麼厲害，反應也不至於這麼快吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그쪽 아가씨의 회사로부터 긴급한 협조 요청이 있었다네.","JPN":"そちらのお嬢さんの会社から緊急の協力要請が届いたんだ。","ENG":"Your company made an emergency call for help.","TWN":"是那位小姐的公司向我們請求緊急支援。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 사태 때 큰 활약을 한 코핀 컴퍼니가 그렇게 당황할 정도라면 매우 심각한 일일 거라고 확신했지.","JPN":"リプレイサー事件の時に大活躍したコフィンカンパニーが\\nそこまで切羽詰まっているとなると、非常に深刻な状況だと確信した。","ENG":"The Coffin Company made a big impact during the Replacer incident. If a company that powerful was in serious trouble, we figured the situation must be very grave.","TWN":"連在克隆集團事件時那麼活躍的科芬公司，都那麼驚慌的話，那事情應該很嚴重。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서 내 독단으로 함대를 끌고 온 거야.","JPN":"だから私の独断で艦隊を連れてきたわけだ。","ENG":"So I brought the fleet on my own authority.","TWN":"因此我當機立斷帶著艦隊來找你們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회사에서…….","JPN":"会社が……","ENG":"My company called you...","TWN":"公司……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무튼 이대로 가만히 있을 수는 없어.","JPN":"とにかく、手をこまねいているわけにはいかない。","ENG":"Anyway, I can’t stay here.","TWN":"總之必須趕快想想辦法！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 괴물이 현실세계로 나오게 놔뒀다간 정말 큰일이 벌어질 거야!","JPN":"あの化け物が現実世界に出てくるまで放っておいたら大惨事になる！","ENG":"If that monster enters the Normalside, it will be a disaster!","TWN":"要是放任那個怪物出現在現實世界，恐怕真的會出大事！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배를 찾기 위해서도 당장 돌아가야 해.","JPN":"先輩を捜すためにも、すぐに戻らないと。","ENG":"We also have to find Shiyoon.","TWN":"我要回去看看，而且也要去找前輩！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내 생각도 같아. 그 괴물이 현실세계로 나오게 되면 걷잡을 수 없겠지.","JPN":"俺も同感だ。あの化け物が現実世界に出てきたら手に負えない事態になるだろう。","ENG":"I agree. We can’t let that monster enter the Normalside.","TWN":"我同意，萬一那個怪物真的出現在現實世界，事情可能會一發不可收拾。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 전에 막아야 해.","JPN":"その前に止めるべきだ。","ENG":"We have to stop it before it does.","TWN":"必須在那之前阻止他！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"동감일세. 당장 돌입 준비를……","JPN":"わかった。すぐに突入する準備を……","ENG":"I feel the same way. We have to prepare for—","TWN":"我也同意，立刻準備……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"긴급 보고! 사령관님! 강력한…… 아주 강력한 침식파가 함대에 접근 중입니다!","JPN":"緊急報告！　司令官！　強力な……非常に強力な侵食波が艦隊に接近中です！","ENG":"Emergency report! Commander! A powerful Corruption Ray is approaching our fleet!","TWN":"司令官，有急事報告！有強烈……非常強烈的侵蝕波正在接近艦隊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"강력하다니, 얼마나 강력하다는 건가? 어디에서 접근 중이고?","JPN":"強力とは、どれくらいの強さだ？　どこから接近しているのか特定を！","ENG":"Powerful? How powerful? From where?","TWN":"是有多強烈？從哪裡接近中？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"모르겠습니다! 모든 측정기가 최대치를 가리켜서 수치 확인이 불가능합니다!","JPN":"不明です！　すべての測定器が最大値を指していて数値観測ができません！","ENG":"I don’t know, ma’am! The readings on all meters reached maximum; we can’t figure it out for sure!","TWN":"無法確定！所有的測定器都指著最大值，因此無法確定正確數值！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"접근 위치는…… 하, 하부 차원! 이쪽 차원으로 급속 부상하고 있습니다!","JPN":"接近位置は……か、下部次元！　こちらの次元に向かって急速に浮上してきます！","ENG":"It’s coming from... the lower dimension! It’s surfacing rapidly!","TWN":"是從……下層次元往這裡的次元快速接近中！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고?!","JPN":"何だと！？","ENG":"What?!","TWN":"你說什麼？！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>크워어어───!!</color>","JPN":"<color=#ff3636>グオオオ───！！</color>","ENG":"<color=#ff3636>GRRRRRRAAAAH───!!</color>","TWN":"<color=#ff3636>轟隆隆───!!</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 관측반! 적 거대 침식체가 불러들인 것으로 추정되는 4종 침식체 다수가 본 함대를 향해 이동 중!</color>","JPN":"<color=#ffd34c>こちら観測班！　敵の巨大侵食体が呼び寄せたと推定される第4種侵食体が複数、本艦隊に向かって接近中！</color>","ENG":"<color=#ffd34c>This is the observation team! Multiple Category 4 C.O.s under the giant C.O.'s control are approaching our fleet!</color>","TWN":"<color=#ffd34c>這裡是觀測組！有大量的4類侵蝕體正朝本艦隊移動中，推測是敵方巨大侵蝕體引來的！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"4종 침식체를 그저 하수인으로 부린다는 건가……? 그것도 다수의 군집을?","JPN":"第4種侵食体をただの手下として操れるということか……？\\nそれも複数だと？","ENG":"It controls Category 4 C.O.s as its minions? A group of them?","TWN":"意思是他可以把4類侵蝕體當手下使喚嗎……？而且還是這麼龐大的數量？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭔지 몰라도 쉽지 않은 싸움이 되겠군.","JPN":"得体の知れない存在だ。厳しい戦いになりそうだな。","ENG":"This won’t be an easy fight.","TWN":"雖然不知道對方是誰，但看來這會是場不輕鬆的戰鬥。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전 함대, 전투준비!","JPN":"全艦隊、戦闘準備！","ENG":"All ships, ready for battle!","TWN":"全體艦隊，準備作戰！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};